import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-applications-list',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './applications-list.component.html',
  styleUrls: ['./applications-list.component.css']
})
export class ApplicationsListComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  historyList: any[] = [];
  isLoading: boolean = true;
  selectedRecruiter: any = null; // 🚀 Gère le recruteur sélectionné pour la pop-up
  selectedJob: any = null;       // 🚀 Gère l'offre sélectionnée pour la pop-up de détails

  ngOnInit() {
    this.fetchCandidateHistory();
  }

  fetchCandidateHistory() {
    const targetUrl = 'http://localhost:3000/api/candidate/history';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de lire votre historique de postulation.");
      return res.json();
    })
    .then(data => {
      this.historyList = data.history || [];
      this.isLoading = false;
      this.cdr.detectChanges();
    })
    .catch(err => {
      console.error("❌ Erreur historique candidat :", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }

  // 🚀 REQUÊTE DYNAMIQUE POUR APPELER LE PROFIL DE L'ENTREPRISE AU CLIC
  onViewRecruiterProfile(recruiterId: number) {
    if (!recruiterId) return;
    const token = localStorage.getItem('token');
    const targetUrl = `http://localhost:3000/api/candidate/profile/details-public/${recruiterId}`;
    
    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => {
      if (!res.ok) throw new Error();
      return res.json();
    })
    .then(data => {
      this.selectedRecruiter = data;
      this.cdr.detectChanges();
    })
    .catch(() => {
      alert("Impossible de charger le profil de l'entreprise.");
    });
  }

  onCloseRecruiterModal() {
    this.selectedRecruiter = null;
    this.cdr.detectChanges();
  }

  // 🚀 INTERCEPTE LE CLIC SUR LE TITRE DU POSTE POUR CONSTUIRE L'OBJET DE LA MODALE
  onViewJobDetails(app: any) {
    if (!app) return;
    this.selectedJob = {
      title: app.job_title || app.title,
      company_name: app.company_name || 'REC',
      contract_type: app.contract_type || 'CDI',
      location: app.location || 'Tunisie',
      missions_desc: app.missions_desc || 'Aucune description des missions disponible.',
      profile_desc: app.profile_desc || 'Aucun prérequis spécifié.',
      skills_desc: app.skills_desc || null,
      languages_desc: app.languages_desc || null,
      expires_at: app.expires_at || null,
      company_logo: app.company_logo || null,
      recruiter_id: app.recruiter_id
    };
    this.cdr.detectChanges();
  }

  onCloseJobModal() {
    this.selectedJob = null;
    this.cdr.detectChanges();
  }

  // 🌟 Découpe les compétences textuelles de la base MySQL pour la boucle Angular
  getSearchJobSkillsArray(skillsText: string): string[] {
    if (!skillsText) return [];
    return skillsText.split(',').map(s => s.trim()).filter(s => s !== '');
  }

  // 🌟 Découpe les langues textuelles de la base MySQL pour la boucle Angular
  getSearchJobLanguagesArray(langText: string): string[] {
    if (!langText) return [];
    return langText.split(',').map(s => s.trim()).filter(s => s !== '');
  }
}
<div class="manage-container">

  <!-- En-tête de la page -->
  <div class="card-header-flex">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-check-fill"></i> Suivi de mes candidatures</h3>
      <p>Consultez l'état d'avancement et les réponses des recruteurs pour vos postes postulés.</p>
    </div>
  </div>

  <!-- 📋 CARTE DU TABLEAU DE SUIVI ASSAINIE -->
  <div class="manage-card-premium">
    <div class="table-wrapper-premium">
      <table class="jobs-table-premium">
        <thead>
          <tr>
            <th class="th-left-padding">Poste / Entreprise</th>
            <th>Date d'envoi</th>
            <th class="th-center-align">Statut</th>
          </tr>
        </thead>
        <tbody>
          
          <!-- ⏳ État de chargement asynchrone -->
          @if (isLoading) {
            <tr>
              <td colspan="3" style="text-align: center; padding: 30px; color: #64748b; font-weight: 500;">
                <i class="bi bi-arrow-clockwise" style="display: inline-block; animation: spin 1s linear infinite; margin-right: 8px;"></i>
                Chargement de votre historique de postulation...
              </td>
            </tr>
          }

          <!-- 🚫 Cas où le catalogue est vide -->
          @if (!isLoading && historyList.length === 0) {
            <tr>
              <td colspan="3" style="text-align: center; padding: 40px; color: #64748b;">
                <i class="bi bi-send-x-fill" style="font-size: 28px; display: block; margin-bottom: 8px; color: #cbd5e1;"></i>
                Vous n'avez pas encore envoyé de candidatures.
              </td>
            </tr>
          }

          <!-- 🚀 RENDU DYNAMIQUE DES LIGNES MYSQL NETTOYÉES -->
          @for (app of historyList; track app.job_id) {
            <tr class="table-row-premium">
              <td class="job-company-cell">
                <span class="job-main-title clickable-job-title" (click)="onViewJobDetails(app)">
                  {{ app.job_title }}
                </span>
                <span class="company-sub-badge clickable-recruiter" (click)="onViewRecruiterProfile(app.recruiter_id)">
                  <i class="bi bi-building-check"></i> {{ app.company_name }}
                </span>
              </td>
              
              <td class="date-text-cell-premium">
                <div class="date-container-premium">
                  <i class="bi bi-calendar3"></i> 
                  <span>{{ app.applied_at | date:'dd/MM/yyyy' }}</span>
                </div>
              </td>
              
              <td class="status-cell-premium">
                <span class="status-badge-fixed" [ngClass]="{
                  'bg-amber': app.status === 'Nouveau' || app.status === 'en_attente',
                  'bg-blue': app.status === 'Entretien',
                  'bg-emerald': app.status === 'retenu' || app.status === 'Acceptée' || app.status === 'Proposition',
                  'bg-red': app.status === 'refuse' || app.status === 'Refusée' || app.status === 'Rejete'
                }">
                  <span class="dot-status"></span>
                  <span class="badge-text-span">
                    {{ app.status === 'Nouveau' || app.status === 'en_attente' ? 'En attente' : app.status === 'retenu' || app.status === 'Acceptée' || app.status === 'Proposition' ? 'Retenu' : app.status === 'refuse' || app.status === 'Refusée' || app.status === 'Rejete' ? 'Refusé' : app.status }}
                  </span>
                </span>
              </td>
            </tr>
          }
          
        </tbody>
      </table>
    </div>
  </div>

  <!-- 🏢 🌟 FEUILLE MODALE : CONSULTATION DU PROFIL COMPLET DE L'ENTREPRISE -->
  @if (selectedRecruiter) {
    <div class="modal-overlay" (click)="onCloseRecruiterModal()">
      <div class="modal-card recruiter-profile-card" (click)="$event.stopPropagation()">
        <div class="modal-header">
          <h3><i class="bi bi-building-fill"></i> Fiche de l'entreprise</h3>
          <button (click)="onCloseRecruiterModal()" class="btn-close-modal"><i class="bi bi-x-lg"></i></button>
        </div>
        <div class="modal-body">
          <div class="recruiter-meta-header">
            <div class="large-avatar-placeholder">
              @if (selectedRecruiter.company_logo) {
                <img [src]="'http://localhost:3000/logos/' + selectedRecruiter.company_logo" alt="Logo">
              } @else {
                <i class="bi bi-building" style="font-size: 32px; color: #cbd5e1;"></i>
              }
            </div>
            <div class="recruiter-main-titles">
              <h4>{{ selectedRecruiter.company_name }}</h4>
              <span class="badge-verified"><i class="bi bi-patch-check-fill"></i> Partenaire Vérifié</span>
            </div>
          </div>

          <div class="recruiter-contact-grid">
            <div class="contact-item"><strong><i class="bi bi-envelope-fill"></i> Email :</strong> <span>{{ selectedRecruiter.email || 'Non spécifié' }}</span></div>
            <div class="contact-item"><strong><i class="bi bi-telephone-fill"></i> Téléphone :</strong> <span>{{ selectedRecruiter.phone || 'Non spécifié' }}</span></div>
            <div class="contact-item span-two"><strong><i class="bi bi-geo-alt-fill"></i> Siège social :</strong> <span>{{ selectedRecruiter.address || 'Non spécifié' }}</span></div>
          </div>

          <div class="detail-block" style="margin-top: 15px;">
            <strong>À propos de l'entreprise :</strong>
            <p class="bio-text-box">{{ selectedRecruiter.company_bio || 'Aucune description fournie par l\'entreprise.' }}</p>
          </div>
        </div>
      </div>
    </div>
  }

  <!-- 👁️ 🌟 FEUILLE MODALE : DETAILS COMPLETS DE L'OFFRE D'EMPLOI SUIVIE -->
  @if (selectedJob) {
    <div class="modal-overlay" (click)="onCloseJobModal()">
      <div class="modal-card" (click)="$event.stopPropagation()">
        
        <div class="modal-header">
          <h3><i class="bi bi-file-earmark-text-fill"></i> Détails de l'offre d'emploi</h3>
          <button (click)="onCloseJobModal()" class="btn-close-modal"><i class="bi bi-x-lg"></i></button>
        </div>

        <div class="modal-body">
          <div class="job-hero-section">
            <div class="job-logo-wrapper">
              <img [src]="selectedJob.company_logo ? 'http://localhost:3000/logos/' + selectedJob.company_logo : 'https://placehold.co'" 
                   (error)="$any($event.target).src='https://placehold.co'"
                   alt="Logo entreprise">
            </div>
            
            <div class="job-meta-content">
              <h4 class="job-main-title">{{ selectedJob.title }}</h4>
              <span class="job-company-link" (click)="onViewRecruiterProfile(selectedJob.recruiter_id)">
                <i class="bi bi-building"></i> {{ selectedJob.company_name }}
              </span>
              
              <div class="job-badges-row">
                <span class="premium-badge badge-contract"><i class="bi bi-file-earmark-text"></i> {{ selectedJob.contract_type }}</span>
                <span class="premium-badge badge-location"><i class="bi bi-geo-alt-fill"></i> {{ selectedJob.location }}</span>
                
                @if (selectedJob.expires_at) {
                  <span class="premium-badge badge-expiration" style="background-color: #fff7ed; color: #c2410c; border-color: #ffedd5; font-weight: 600;">
                    <i class="bi bi-calendar-x-fill" style="color: #ea580c;"></i> Expire le : {{ selectedJob.expires_at | date:'dd/MM/yyyy' }}
                  </span>
                }
              </div>
            </div>
          </div>

          <div class="job-text-block-section">
            <span class="job-block-title"><i class="bi bi-list-task"></i> Missions principales</span>
            <div class="job-block-card">
              <p style="white-space: pre-line; margin: 0; line-height: 1.65; color: #334155;">{{ selectedJob.missions_desc }}</p>
            </div>
          </div>

          <div class="job-text-block-section">
            <span class="job-block-title"><i class="bi bi-person-badge-fill"></i> Profil requis & Prérequis</span>
            <div class="job-block-card">
              <p style="white-space: pre-line; margin: 0; line-height: 1.65; color: #334155;">{{ selectedJob.profile_desc }}</p>
            </div>
          </div>

          @if (selectedJob.skills_desc) {
            <div class="job-text-block-section">
              <span class="job-block-title"><i class="bi bi-tags-fill"></i> Compétences clés & Technologies</span>
              <div class="job-block-card">
                <div class="skills-badge-grid">
                  @for (skill of getSearchJobSkillsArray(selectedJob.skills_desc); track $index) {
                    <span class="skill-tag">
                      <i class="bi bi-check2"></i> {{ skill }}
                    </span>
                  }
                </div>
              </div>
            </div>
          }

          @if (selectedJob.languages_desc) {
            <div class="job-text-block-section">
              <span class="job-block-title"><i class="bi bi-translate"></i> Langues exigées</span>
              <div class="job-block-card">
                <div class="skills-badge-grid">
                  @for (lang of getSearchJobLanguagesArray(selectedJob.languages_desc); track $index) {
                    <span class="skill-tag" style="background-color: #faf5ff; color: #6b21a8; border-color: #f3e8ff;">
                      <i class="bi bi-globe"></i> {{ lang }}
                    </span>
                  }
                </div>
              </div>
            </div>
          }

